import { serializeError } from "../constants/errors.mjs";
export const RESPONSE_EVENT = 'RESPONSE_EVENT';
export const createResponseMessage = (id, success, payload, deviceIdentity = undefined) => {
  if (success) return {
    event: RESPONSE_EVENT,
    type: RESPONSE_EVENT,
    id,
    success: true,
    payload,
    device: deviceIdentity
  };
  return {
    event: RESPONSE_EVENT,
    type: RESPONSE_EVENT,
    id,
    success: false,
    error: serializeError(payload),
    device: deviceIdentity
  };
};